function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: unparseable input: ${JSON.stringify(str)}`);
  }

  if (/^\d+$/.test(str)) return parseInt(str, 10);

  const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };
  // ms before m so the two-letter unit takes precedence in alternation
  const TOKEN = /^(\d+)(ms|s|m|h|d)/;

  let total = 0;
  let rest = str;
  while (rest.length > 0) {
    const match = TOKEN.exec(rest);
    if (!match) throw new Error(`parseDuration: unparseable input: ${JSON.stringify(str)}`);
    total += parseInt(match[1], 10) * UNITS[match[2]];
    rest = rest.slice(match[0].length);
  }
  return total;
}

